#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, A;
        scanf("%lld %lld", &N, &A);
        long long s = (long long) sqrt((double) N);
        while ((s + 1) * (s + 1) <= N) ++s;
        while (s * s > N) --s;
        printf("%lld\n", s * A);
    }
    return 0;
}

