const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = BigInt(input[idx++]);
  const A = BigInt(input[idx++]);
  // integer sqrt for BigInt using binary search
  let low = 0n, high = N;
  while (low <= high) {
    const mid = (low + high) >> 1n;
    if (mid * mid <= N) {
      low = mid + 1n;
    } else {
      high = mid - 1n;
    }
  }
  const s = high; // floor sqrt
  results.push((s * A).toString());
}
console.log(results.join('\n'));
